import{_ as e,o as n,c as s,aw as a}from"./chunks/framework.Dq2onT5h.js";const t=JSON.parse('{"title":"Sequencing","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Sequencing | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"learn/sequencing/overview.md","filePath":"learn/sequencing/overview.md","lastUpdated":1764781917000}');const o=e({name:"learn/sequencing/overview.md"},[["render",function(e,t,o,l,c,r){return n(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="sequencing" tabindex="-1">Sequencing <a class="header-anchor" href="#sequencing" aria-label="Permalink to &quot;Sequencing&quot;">​</a></h1><p>Sequencing is the essential first step for handling your transactions. Think of it as an organizer that takes all incoming transactions, puts them in a clear order, and then groups them into batches. This process is vital for keeping everything consistent and making the chain run. Evolve uses a &quot;Sequencing Interface&quot; with key functions like submitting, retrieving, and verifying these transaction batches, ensuring smooth communication between the chain and the sequencing mechanism, which often acts as a bridge to the underlying network.</p><h2 id="sequencing-interface" tabindex="-1">Sequencing Interface <a class="header-anchor" href="#sequencing-interface" aria-label="Permalink to &quot;Sequencing Interface {#sequencing-interface}&quot;">​</a></h2><p><a href="https://github.com/evstack/ev-node/blob/main/core/sequencer/sequencing.go#L11" target="_blank" rel="noreferrer">Sequencing Interface</a> defines a sequencing interface for communicating between any sequencing network and Evolve. The key functions of the interface are defined as shown below.</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// Sequencer is a generic interface for a sequencer</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Sequencer</span><span style="color:#B8A6FF;"> interface</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // SubmitBatchTxs submits a batch of transactions  to sequencer</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // Id is the unique identifier for the target chain</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // Batch is the batch of transactions to submit</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // returns an error if any from the sequencer</span></span>\n<span class="line"><span style="color:#94EEFF;"> SubmitBatchTxs</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">ctx </span><span style="color:#CDA4EB;">context</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Context</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> req </span><span style="color:#CDA4EB;">SubmitBatchTxsRequest</span><span style="color:#767676;">)</span><span style="color:#767676;"> (</span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">SubmitBatchTxsResponse</span><span style="color:#767676;">,</span><span style="color:#B8A6FF;"> error</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"> // GetNextBatch returns the next batch of transactions from sequencer to</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // Id is the unique identifier for the target chain</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // LastBatchHash is the cryptographic hash of the last batch received by the</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // MaxBytes is the maximum number of bytes to return in the batch</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // returns the next batch of transactions and an error if any from the sequencer</span></span>\n<span class="line"><span style="color:#94EEFF;"> GetNextBatch</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">ctx </span><span style="color:#CDA4EB;">context</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Context</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> req </span><span style="color:#CDA4EB;">GetNextBatchRequest</span><span style="color:#767676;">)</span><span style="color:#767676;"> (</span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">GetNextBatchResponse</span><span style="color:#767676;">,</span><span style="color:#B8A6FF;"> error</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;"> // VerifyBatch verifies a batch of transactions received from the sequencer</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // Id is the unique identifier for the target chain</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // BatchHash is the cryptographic hash of the batch to verify</span></span>\n<span class="line"><span style="color:#A0A0A0;"> // returns a boolean indicating if the batch is valid and an error if any from the sequencer</span></span>\n<span class="line"><span style="color:#94EEFF;"> VerifyBatch</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">ctx </span><span style="color:#CDA4EB;">context</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Context</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> req </span><span style="color:#CDA4EB;">VerifyBatchResponse</span><span style="color:#767676;">)</span><span style="color:#767676;"> (</span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">VerifyBatchResponse</span><span style="color:#767676;">,</span><span style="color:#B8A6FF;"> error</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><p>It mainly consists of:</p><ul><li><code>SubmitBatchTxs</code> relays the chain transactions from Evolve chain to the sequencing network</li><li><code>GetNextBatch</code> returns the next batch of transactions along with a deterministic timestamp</li><li><code>VerifyBatch</code> validates the sequenced batch</li></ul><h2 id="sequencing-implementations" tabindex="-1">Sequencing Implementations <a class="header-anchor" href="#sequencing-implementations" aria-label="Permalink to &quot;Sequencing Implementations {#sequencing-implementations}&quot;">​</a></h2><p>An implementation of the sequencing interface mainly acts as a middleware that connects Evolve chain and the sequencing layer. It implements the sequencing interface functions described above. There are several implementations of the sequencer available in Evolve:</p><ul><li><a href="./single">single-sequencer</a> - The simplest and most widely used sequencing model, where a single node (the sequencer) is responsible for ordering transactions and producing blocks.</li><li><a href="./based">based-sequencer</a> - A decentralized sequencing model where transaction ordering is determined by the base layer, and every full node acts as its own proposer.</li></ul>',10)])])}]]);export{t as __pageData,o as default};
